INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('platre-staff-tete-de-lion', 'platre-staff-tete-de-lion', 'platres', 'Plâtre pour Staff Tête de Lion', 'Sac 40 kg', 'Plâtre extra blanc pour la réalisation de travaux de staff et de décoration intérieure.', 'Le Plâtre pour Staff Tête de Lion est un plâtre décoratif extra blanc d''origine égyptienne, idéal pour la confection de moulures, corniches, rosaces et tout ouvrage de staff. Sa finesse et sa blancheur garantissent un résultat lisse et impeccable. Distribué par NSDPF, Abidjan, Côte d''Ivoire.', 1, 0);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('platre-plaque-deco-classique', 'platre-plaque-deco-classique', 'plaques-deco', 'Plaque Décorative Plâtre Classique', 'Plaque (unité)', 'Plaque décorative en plâtre à motifs classiques ornementés pour portes et cloisons.', 'Cette plaque décorative en plâtre présente un relief classique richement orné de volutes et de rosaces, destinée à l''habillage de portes, de cloisons ou de façades intérieures. Elle apporte une touche d''élégance architecturale à tout espace résidentiel ou commercial.', 1, 1);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('platre-plaque-deco-moderne', 'platre-plaque-deco-moderne', 'plaques-deco', 'Plaque Décorative Plâtre Moderne', 'Plaque (unité)', 'Plaque décorative en plâtre à motifs géométriques modernes pour portes et cloisons.', 'Cette plaque en plâtre au design contemporain et géométrique convient à l''habillage de portes ou de panneaux muraux. Ses lignes épurées et ses encadrements en relief s''intègrent parfaitement dans les intérieurs modernes et minimalistes.', 0, 2);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('lambris-pvc-deco', 'lambris-pvc-deco', 'plaques-deco', 'Lambris PVC Décoration Murale', 'Panneau (lot)', 'Panneaux lambris PVC imitation bois pour habillage mural intérieur.', 'Ces panneaux en PVC à effet bois (chêne clair, wengé, hêtre, rouge) permettent un habillage rapide et durable des murs et plafonds intérieurs. Légers, faciles à poser et résistants à l''humidité, ils conviennent aux pièces à vivre, bureaux et commerces.', 0, 3);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('tole-ondulee-coloree', 'tole-ondulee-coloree', 'plaques-deco', 'Tôle Ondulée Colorée', 'Barre / Feuille (lot)', 'Tôles ondulées colorées pour couverture et bardage de bâtiments.', 'Ces tôles ondulées disponibles en plusieurs coloris (orange, vert, rouge) sont utilisées pour la couverture de toitures, hangars et bâtiments agricoles ou commerciaux. Leur résistance aux intempéries et leur finition colorée garantissent durabilité et esthétique.', 0, 4);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('filasse-naturelle', 'filasse-naturelle', 'filasse-etancheite', 'Filasse Naturelle', 'Pelote / Botte', 'Filasse naturelle pour l''étanchéité des joints de plomberie.', 'La filasse naturelle est indispensable pour assurer l''étanchéité des raccords de plomberie, robinetterie et canalisations. Ses fibres souples et résistantes se compriment parfaitement dans les filetages pour prévenir toute fuite d''eau.', 1, 5);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('tuyau-pvc-souple-shoshona', 'tuyau-pvc-souple-shoshona', 'filasse-etancheite', 'Tuyau PVC Souple Shoshona', 'Rouleau', 'Tuyau PVC souple orange pour adduction d''eau et irrigation.', 'Le tuyau PVC souple Shoshona (coloris orange) est conçu pour les réseaux d''adduction d''eau, d''irrigation et les installations sanitaires légères. Sa souplesse facilite la pose dans des configurations complexes, et sa résistance à la pression garantit une longue durée de service.', 0, 6);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('tuyau-pex-al-pex-ifan', 'tuyau-pex-al-pex-ifan', 'filasse-etancheite', 'Tuyau Multicouche PEX-AL-PEX IFAN Laser', 'Rouleau', 'Tuyau multicouche PEX-AL-PEX pour plomberie eau chaude/froide et chauffage.', 'Le tuyau multicouche IFAN Laser (PEX-AL-PEX) combine la souplesse du PEX et la rigidité de l''aluminium pour des installations de plomberie sanitaire, eau chaude et chauffage au sol. Sa structure triaxiale résiste aux hautes températures et aux chocs, garantissant une installation fiable et durable.', 0, 7);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('tuyau-pvc-industriel-jaune', 'tuyau-pvc-industriel-jaune', 'filasse-etancheite', 'Tuyau PVC Industriel Souple', 'Rouleau', 'Tuyau PVC industriel souple jaune pour usage industriel et agricole.', 'Ce tuyau PVC industriel souple (coloris jaune, diamètre 20 mm, épaisseur 2,0 mm) est adapté aux applications industrielles, agricoles et de génie civil nécessitant une grande résistance à la pression et aux agents chimiques courants.', 0, 8);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('barre-armature-fer', 'barre-armature-fer', 'filasse-etancheite', 'Barre d''Armature FAN', 'Barre (lot)', 'Barres d''armature métalliques pour béton armé et structures de construction.', 'Ces barres d''armature FAN conditionnées en fagots sont destinées au renforcement des ouvrages en béton armé (dalles, poteaux, poutres, fondations). Elles offrent une excellente tenue mécanique et une bonne adhérence au béton pour des structures durables.', 0, 9);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('mortier-colle-carrelage', 'mortier-colle-carrelage', 'colles-enduits', 'Mortier Colle pour Carrelage', 'Sac 25 kg', 'Mortier-colle pour la pose de carrelage en intérieur et en extérieur.', 'Ce mortier-colle en poudre est formulé pour la pose de carrelage céramique, grès et pierre sur sol et mur, en intérieur comme en extérieur. Sa forte adhérence et sa résistance aux variations thermiques en font le choix idéal pour les chantiers exigeants.', 0, 10);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('sdpf-ciment-colle', 'sdpf-ciment-colle', 'colles-enduits', 'SDPF Ciment Colle', 'Sac 25 kg', 'Ciment-colle SDPF pour carrelage intérieur et extérieur.', 'Le Ciment Colle SDPF est un produit de la gamme propre de la société, adapté à la pose de carreaux céramiques et de grès sur mortier sec ou béton, en intérieur et extérieur. Sa formulation assure une excellente prise et une résistance à long terme aux sollicitations mécaniques et à l''humidité.', 0, 11);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('leclassic-ciment-colle', 'leclassic-ciment-colle', 'colles-enduits', 'LeCLASSIC Ciment Colle', 'Sac 25 kg', 'Ciment-colle LeCLASSIC qualité supérieure pour carrelage.', 'LeCLASSIC Ciment Colle est une colle à carrelage de qualité supérieure, idéale pour la pose de carreaux en intérieur et en extérieur sur tout type de support. Sa résistance à l''eau et sa souplesse en font un produit particulièrement adapté aux zones humides (salles de bain, cuisines, terrasses).', 0, 12);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('caiman-vernis-eau', 'caiman-vernis-eau', 'colles-enduits', 'Caïman Vernis à Eau', 'Bidon 5 L / Bidon 1 L', 'Vernis à eau Caïman pour la protection et la finition des surfaces bois.', 'Le Vernis à Eau Caïman, fabriqué en Côte d''Ivoire, est un vernis en phase aqueuse destiné à la protection et à la mise en valeur des surfaces en bois (parquets, meubles, boiseries). Séchage rapide, faible odeur et facilité d''application en font le produit de finition de référence pour les professionnels et les particuliers.', 0, 13);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('douba-sel-iodise', 'douba-sel-iodise', 'colles-enduits', 'Sel Fin Iodisé Raffiné Douba', 'Sac 25 kg', 'Sel fin iodisé raffiné d''Égypte pour usage alimentaire et industriel.', 'Le sel fin iodisé raffiné Douba (Sina and Siwa), produit d''Égypte, est commercialisé en sac de 25 kg pour les usages alimentaires collectifs et industriels. Sa pureté et son enrichissement en iode répondent aux normes de qualité internationales.', 0, 14);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('lavabo-encastre-zolux', 'lavabo-encastre-zolux', 'sanitaires', 'Lavabo Encastré Carré ZOLUX', 'Pièce', 'Lavabo en céramique carrée à encastrer pour salle de bain moderne.', 'Le lavabo encastré ZOLUX au design carré épuré est fabriqué en céramique blanche de haute qualité. Il s''intègre élégamment dans les plans de travail de salle de bain contemporains, offrant robustesse et facilité d''entretien.', 0, 15);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('wc-luxe-monobloc-zotoz', 'wc-luxe-monobloc-zotoz', 'sanitaires', 'WC Luxe Monobloc ZOTOZ', 'Pièce', 'WC monobloc luxe en céramique blanche pour installation sanitaire haut de gamme.', 'Le WC Luxe Monobloc ZOTOZ est une cuvette tout-en-un en céramique blanche de qualité supérieure, au design carré contemporain. Son réservoir intégré et son abattant inclus facilitent l''installation et l''entretien, pour un rendu élégant dans toute salle de bain ou WC indépendant.', 1, 16);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('lavabo-ordinaire-zotoz', 'lavabo-ordinaire-zotoz', 'sanitaires', 'Lavabo Ordinaire ZOTOZ', 'Pièce', 'Lavabo rond en céramique pour installation murale standard.', 'Le lavabo ordinaire ZOTOZ en céramique blanche à vasque arrondie est conçu pour une installation murale simple et rapide. Son format compact le rend idéal pour les petites salles de bain, les WC et les espaces sanitaires collectifs.', 0, 17);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('lavabo-luxe-colonne-zotoz', 'lavabo-luxe-colonne-zotoz', 'sanitaires', 'Lavabo Luxe sur Colonne ZOTOZ', 'Pièce (lavabo + pieds)', 'Lavabo luxe sur colonne en céramique pour salle de bain élégante.', 'L''ensemble Lavabo Luxe + Pieds ZOTOZ offre un support autoportant en céramique blanche, alliant style classique et praticité. La colonne dissimule les arrivées d''eau pour une installation soignée, adaptée aux salles de bain résidentielles et aux espaces hôteliers.', 0, 18);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('wc-ordinaire-totot', 'wc-ordinaire-totot', 'sanitaires', 'WC Ordinaire Deux Pièces TOTOT', 'Pièce', 'WC deux pièces en céramique blanche pour installation sanitaire standard.', 'Le WC Ordinaire TOTOT en deux pièces (cuvette + réservoir séparé) est la solution économique et fiable pour les installations sanitaires résidentielles et commerciales. Sa conception classique facilite l''entretien et le remplacement des pièces.', 0, 19);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('wc-luxe-couleur-zotoz', 'wc-luxe-couleur-zotoz', 'sanitaires', 'WC Luxe Couleur ZOTOZ', 'Pièce', 'WC monobloc luxe en céramique colorée pour une salle de bain personnalisée.', 'Le WC Luxe Couleur ZOTOZ se distingue par sa finition bicolore originale (rose et blanc effet marbre) sur une cuvette monobloc au design carré premium. Il permet de créer une salle de bain unique et affirmée, tout en conservant le confort et la durabilité de la céramique de qualité.', 0, 20);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('brouette-chantier-coloree', 'brouette-chantier-coloree', 'outillage-quincaillerie', 'Brouette de Chantier Colorée', 'Pièce', 'Brouette de chantier à bac plastique coloré pour transport de matériaux.', 'Ces brouettes de chantier à bac en polyéthylène haute densité (disponibles en jaune, bleu, orange et vert) offrent légèreté et résistance pour le transport de mortier, gravats et matériaux de construction sur chantier. Leur châssis métallique robuste et leur roue gonflable assurent stabilité et maniabilité.', 0, 21);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('clou-beton-concrete-nail', 'clou-beton-concrete-nail', 'outillage-quincaillerie', 'Clou Béton Concrete Nail', 'Boîte', 'Clous pour béton et maçonnerie, pour fixation sur supports durs.', 'Les clous béton Concrete Nail (Made in China) sont des fixations en acier trempé destinées à l''ancrage direct dans le béton, la brique et les matériaux de maçonnerie. Leur pointe durcie permet la pose sans perçage préalable à l''aide d''un marteau.', 0, 22);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('clous-tete-plate-syo', 'clous-tete-plate-syo', 'outillage-quincaillerie', 'Clous Tête Plate SYO', 'Boîte', 'Clous à tête plate SYO pour charpente, menuiserie et assemblage bois.', 'Les clous tête plate SYO (Toujours à la pointe de la qualité) sont des clous en acier galvanisé destinés aux travaux de charpente, menuiserie et assemblage de bois. Leur tête plate discrète permet un enfoncement affleurant pour un rendu net et professionnel.', 0, 23);
INSERT INTO products (id, slug, category_id, name, format, desc_short, desc_long, featured, sort_order) VALUES ('clous-feutre-galv-kol', 'clous-feutre-galv-kol', 'outillage-quincaillerie', 'Clous Galvanisés pour Feutre KOL', 'Boîte 25 pièces', 'Clous galvanisés pour la fixation de feutre bitumé et membrane d''étanchéité.', 'Les Galv Felt Nails KOL (taille 1", 25 pièces, Made in China) sont des clous à large tête en acier galvanisé spécialement conçus pour la fixation de feutre bitumé, membranes d''étanchéité et sous-couches de toiture. Leur galvanisation assure une bonne résistance à la corrosion.', 0, 24);
